        mockTitle: { pt: "SW3 · MOMENTARY — aba CONFIGURAÇÕES", en: "SW3 · MOMENTARY — SETTINGS tab", es: "SW3 · MOMENTARY — pestaña AJUSTES" },
        mockType: "sw-momentary",
